import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.util.List;

@RestController
@RequestMapping("/api/reports")
public class ReportController {

    @Autowired
    private ReportService reportService;

    @GetMapping("/{fieldId}")
    public ResponseEntity<List<Report>> getReportsByField(@PathVariable Long fieldId) {
        List<Report> reports = reportService.getReportsByField(fieldId);
        return ResponseEntity.ok(reports);
    }

    @PostMapping
    public ResponseEntity<Report> createReport(@Valid @RequestBody Report report) {
        Report createdReport = reportService.createReport(report);
        return ResponseEntity.status(201).body(createdReport);
    }

    @GetMapping("/{fieldId}/{reportId}")
    public ResponseEntity<Report> getReportById(@PathVariable Long fieldId, @PathVariable Long reportId) {
        Report report = reportService.getReportById(fieldId, reportId);
        return ResponseEntity.ok(report);
    }

    @PutMapping("/{fieldId}/{reportId}")
    public ResponseEntity<Report> updateReport(@PathVariable Long fieldId, @PathVariable Long reportId, @Valid @RequestBody Report report) {
        Report updatedReport = reportService.updateReport(fieldId, reportId, report);
        return ResponseEntity.ok(updatedReport);
    }

    @DeleteMapping("/{fieldId}/{reportId}")
    public ResponseEntity<Void> deleteReport(@PathVariable Long fieldId, @PathVariable Long reportId) {
        reportService.deleteReport(fieldId, reportId);
        return ResponseEntity.noContent().build();
    }
}
